import{_ as t,c as a,o as n,ag as o}from"./chunks/framework.Dj4VfQLU.js";const u=JSON.parse('{"title":"Installation Overview","description":"","frontmatter":{"icon":"clipboard-question"},"headers":[],"relativePath":"installation-overview.md","filePath":"installation-overview.md"}'),i={name:"installation-overview.md"};function r(s,e,l,c,d,p){return n(),a("div",null,e[0]||(e[0]=[o('<h1 id="installation-overview" tabindex="-1">Installation Overview <a class="header-anchor" href="#installation-overview" aria-label="Permalink to &quot;Installation Overview&quot;">​</a></h1><p>BetterTaxi is designed to be easy to deploy and operate out of the box. The system uses a <strong>containerized architecture</strong> with Docker to ensure consistency, reduce setup complexity, and eliminate manual dependency installation.</p><p>For most users, deploying the entire stack on a <strong>single server instance</strong> is recommended to get started quickly. This includes the backend services, database, admin panel, Redis cache, and NGINX for routing and web access.</p><p>As your operation scales, components such as the <strong>database</strong>, <strong>Redis</strong>, or <strong>admin panel</strong> can be moved to dedicated servers for improved performance and resilience.</p><h4 id="🔄-installation-flow-at-a-glance" tabindex="-1">🔄 Installation Flow (At a Glance) <a class="header-anchor" href="#🔄-installation-flow-at-a-glance" aria-label="Permalink to &quot;🔄 Installation Flow (At a Glance)&quot;">​</a></h4><ol><li><strong>Download the ZIP Package</strong><br> Unpack the full BetterTaxi bundle on your server.</li><li><strong>Run the One-Line Setup Script</strong><br> This script installs Docker, configures environment variables, builds images, and starts all services.</li><li><strong>Configure DNS &amp; SSL (Manual Step)</strong><br> Point your domain to the server IP and secure it with SSL (e.g., via Cloudflare).</li><li><strong>Access the Admin Panel</strong><br> Once setup completes, log into the admin panel to: <ul><li>Add API keys (e.g., SMS, payments)</li><li>Set up pricing zones</li><li>Manage branding and basic system preferences</li></ul></li><li><strong>Compile Mobile Apps</strong><br> Build the customer and driver apps using Flutter and your Firebase credentials.</li><li><strong>Go Live</strong><br> After testing, configure monitoring and prepare for production traffic.</li></ol><blockquote><p><strong>Note:</strong> Server performance should be monitored periodically. As demand increases, consider scaling out by isolating services (e.g., database, Redis, or GraphQL gateway).</p></blockquote>',7)]))}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
